private string $defaultModel;

public function __construct()
{
    $this->key = env('GOOGLE_GEMINI_KEY') ?? env('OPEN_AI_KEY'); 
    // Atualizado para o padrão mais seguro do Google
    $this->defaultModel = "gemini-flash-latest"; 
}

// Agora o método aceita um segundo parâmetro opcional

    // Agora o método aceita um segundo parâmetro opcional
    public function generateContent(string $prompt, ?string $modelOverride = null)
    {
        $modelToUse = $modelOverride ?? $this->defaultModel;

        try {
            $response = Http::timeout(60)->post(
                "https://generativelanguage.googleapis.com/v1beta/models/{$modelToUse}:generateContent?key={$this->key}",
                ['contents' => [['parts' => [['text' => $prompt]]]]]
            );

            if ($response->failed()) {
                $errorBody = $response->body();
                Log::error("Gemini API Error [{$modelToUse}]: " . $errorBody);
                $errorMessage = $response->json()['error']['message'] ?? 'Erro desconhecido na API do Gemini';
                throw new Exception("Erro na IA: " . $errorMessage);
            }

            $text = $response->json()['candidates'][0]['content']['parts'][0]['text'] ?? null;

            if (!$text) {
                Log::error("Gemini API Empty Response [{$modelToUse}]: " . $response->body());
                throw new Exception("A IA não retornou conteúdo. Tente novamente em instantes.");
            }

            return $text;

        } catch (Exception $e) {
            Log::error("Gemini Exception: " . $e->getMessage());
            throw $e;
        }
    }
}

     * É um ótimo ponto de partida porque retorna um feed XML puro e determinístico.
     */
    public function scrape(): array
    {
        // Ampliei o termo para "edital inovação" para garantir que a gente sempre ache
        // notícias e você veja a mágica do scraper rodando na prática!
        $termos = urlencode('edital inovação');
        $url = "https://news.google.com/rss/search?q={$termos}&hl=pt-BR&gl=BR";

        $resultados = [];

        try {
            // Em vez de simplexml_load_file q as vezes o google bloqueia por faltar User-Agent,
            // usamos o Facade Http nativo do Laravel passando que somos um navegador!
            $response = \Illuminate\Support\Facades\Http::withHeaders([
                'User-Agent' => 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36'
            ])->get($url);

            if (!$response->successful()) {
                Log::error("GoogleNewsRssScraper: Falha na requisição / Status: " . $response->status());
                return [];
            }

            // O PHP parseia o texto XML para um Object com base na string que o Http pegou
            $xml = simplexml_load_string($response->body());

            // O XML de RSS tem `<channel>` e dentro de channel vários `<item>`
            // Cada item é uma notícia.
            if (isset($xml->channel->item)) {
                foreach ($xml->channel->item as $noticia) {

                    // Converte os dados do XML para string (tipo seguro do PHP)
                    $tituloString = (string) $noticia->title;
                    $linkString = (string) $noticia->link;
                    // Hash o link pq ele é único e a url original vem camuflada no google news
                    $codigoExterno = md5($linkString);
                    // extrai publisher do title, google news bota publisher no final "- Publisher"
                    $publisher = explode(' - ', $tituloString);
                    $orgao = trim(end($publisher));

                    if (empty($orgao)) {
                        $orgao = 'Google News / Governo';
                    }

                    $resultados[] = [
                        'titulo' => $tituloString,
                        'codigo_externo' => 'googlenews_' . $codigoExterno,
                        'orgao' => $orgao,
                        'email_contato' => null, // GNews não provê isso
                        'modalidade' => 'Oportunidade Listada (RSS)',
                        'orcamento_global' => null,
                        'publico_alvo' => null,
                        'temas' => 'Notícia sobre edital de inovação',
                        'trl_min' => null,
                        'trl_max' => null,
                        // Data de publicação do RSS "pubDate" convertida p BD
                        'data_abertura' => date('Y-m-d', strtotime((string)$noticia->pubDate)),
                        'data_encerramento' => null, // não se sabe só lendo noticia
                        'status' => 'Em breve', // Oportunidade via news sempre entra pendente
                        'url_oficial' => $linkString,
                    ];
                }
            }
        } catch (\Exception $e) {
            Log::error("GoogleNewsRssScraper: Ocorreu um erro no parsing do XML: " . $e->getMessage());
        }

        return $resultados;
    }
}

     * Varrer o site oficial de editais da Finep.
     */
    public function scrape(): array
    {
        $url = 'http://www.finep.gov.br/chamadas-publicas?situacao=aberta';
        $client = new Client();

        $resultados = [];

        try {
            // "Pede" o HTML da URL para o Goutte (ele simula um Browser!)
            $crawler = $client->request('GET', $url);

            // No Finep, eles usam a classe '.item' para cada edital no HTML.
            // Para encontrar o título: .item h3 a (o link com titulo)
            $crawler->filter('.item')->each(function ($node) use (&$resultados) {

                $tituloNode = $node->filter('h3 a');
                if ($tituloNode->count() === 0) return;

                $tituloString = trim($tituloNode->text());
                $linkHref = $tituloNode->attr('href');

                if (strpos($linkHref, 'http') === false) {
                    $linkHref = 'http://www.finep.gov.br' . $linkHref;
                }

                $partes = explode('/', $linkHref);
                $codigoExterno = end($partes);
                if (empty($codigoExterno)) {
                     $codigoExterno = md5($linkHref);
                }

                // Extraindo o Tema real do HTML
                $temasNode = $node->filter('.tema span');
                $temasText = $temasNode->count() > 0 ? trim($temasNode->text()) : 'Inovação Geral';

                // Extraindo Data de Publicação
                $dataNode = $node->filter('.data_pub span');
                $dataPub = $dataNode->count() > 0 ? \Carbon\Carbon::createFromFormat('d/m/Y', trim($dataNode->text()))->format('Y-m-d') : date('Y-m-d');

                $resultados[] = [
                    'titulo' => $tituloString,
                    'codigo_externo' => 'finep_' . $codigoExterno,
                    'orgao' => 'Finep',
                    'email_contato' => null, 
                    'modalidade' => 'Subvenção / Financiamento',
                    'orcamento_global' => null, 
                    'publico_alvo' => 'Empresas e ICTs',
                    'temas' => $temasText,
                    'trl_min' => null,
                    'trl_max' => null,
                    'data_abertura' => $dataPub, 
                    'data_encerramento' => null,
                    'status' => 'Aberto',
                    'url_oficial' => $linkHref,
                ];
            });

        } catch (\Exception $e) {
            Log::error("FinepScraper: Falha ao varrer Finep HTML: " . $e->getMessage());
        }

        return $resultados;
    }
}

